def cmd_skills(args):
    """Manage Claude Code skills under ~/.claude/skills/."""
    from lib import skill_registry, skill_sync

    action = args.skills_action

    def _targets():
        if getattr(args, 'id', None):
            if args.id not in skill_registry.SKILLS:
                print(f"unknown skill id: {args.id}")
                print(f"known ids: {', '.join(skill_registry.all_ids())}")
                sys.exit(2)
            return [args.id]
        return skill_registry.all_ids()
